import os
from pathlib import Path


def _add_graphviz_bin() -> None:
    root = Path(__file__).resolve().parents[3]
    graphviz_bin = root / "Graphviz" / "bin"
    if not graphviz_bin.exists():
        return

    graphviz_bin_str = str(graphviz_bin)
    current_path = os.environ.get("PATH", "")
    path_entries = current_path.split(os.pathsep) if current_path else []
    if graphviz_bin_str not in path_entries:
        os.environ["PATH"] = graphviz_bin_str + os.pathsep + current_path if current_path else graphviz_bin_str

    add_dll_directory = getattr(os, "add_dll_directory", None)
    if add_dll_directory is not None:
        add_dll_directory(graphviz_bin_str)


def _configure_deepseek() -> None:
    os.environ.setdefault("OPENAI_BASE_URL", "https://api.deepseek.com")
    os.environ.setdefault("OPENAI_API_KEY", "sk-888836266e66459dafbcf411a4f91709")


_add_graphviz_bin()
_configure_deepseek()
